import{_ as r,o as t,c as a,ag as o}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Hardware requirements","description":"What you need to run a profitable prover.","frontmatter":{"description":"What you need to run a profitable prover."},"headers":[],"relativePath":"provers/hardware.md","filePath":"provers/hardware.md","lastUpdated":1777130260000}'),i={name:"provers/hardware.md"};function n(s,e,l,d,h,c){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="hardware-requirements" tabindex="-1">Hardware requirements <a class="header-anchor" href="#hardware-requirements" aria-label="Permalink to &quot;Hardware requirements&quot;">​</a></h1><p>A Prova prover doesn&#39;t need exotic hardware. The protocol is <strong>disk-bound, not CPU-bound</strong> — no PoRep, no SNARKs, no GPU.</p><h2 id="minimum" tabindex="-1">Minimum <a class="header-anchor" href="#minimum" aria-label="Permalink to &quot;Minimum&quot;">​</a></h2><ul><li><strong>CPU:</strong> 4 cores (2.0 GHz+)</li><li><strong>RAM:</strong> 8 GB</li><li><strong>Disk:</strong> anything ≥ 1 TB. SATA SSD or NVMe preferred. Spinning rust works for cold storage.</li><li><strong>Network:</strong> symmetric 100 Mbps. Real upload, not consumer-asymmetric.</li><li><strong>Connection:</strong> real IP, real DNS. No CGNAT.</li><li><strong>OS:</strong> Linux (Ubuntu 22.04+, Debian 12+, RHEL 9+ tested). macOS works for dev. Windows untested.</li></ul><h2 id="recommended-10-tb-tier" tabindex="-1">Recommended (10 TB tier) <a class="header-anchor" href="#recommended-10-tb-tier" aria-label="Permalink to &quot;Recommended (10 TB tier)&quot;">​</a></h2><ul><li><strong>CPU:</strong> 8 cores</li><li><strong>RAM:</strong> 32 GB</li><li><strong>Disk:</strong> 10 TB NVMe or 4× 4 TB SSD ZFS RAID-Z1. ECC where possible.</li><li><strong>Network:</strong> 1 Gbps symmetric. Multi-homed if you can.</li><li><strong>Power:</strong> UPS. Single power loss during a proof = missed proof = slash.</li></ul><h2 id="at-scale-100-tb" tabindex="-1">At scale (100 TB+) <a class="header-anchor" href="#at-scale-100-tb" aria-label="Permalink to &quot;At scale (100 TB+)&quot;">​</a></h2><ul><li>Server-grade hardware. Hetzner SX-line, OVH bare metal, used Dell R7xx with shelves.</li><li>ZFS or btrfs with checksumming and scrubbing.</li><li>Two upstream providers (BGP if you&#39;re feeling spicy).</li><li>Cooling. Real cooling.</li></ul><h2 id="what-disk-shape" tabindex="-1">What disk shape <a class="header-anchor" href="#what-disk-shape" aria-label="Permalink to &quot;What disk shape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Disk</th><th>Good for</th><th>Notes</th></tr></thead><tbody><tr><td><strong>NVMe</strong></td><td>Hot tier, fast retrievals</td><td>Most expensive per byte</td></tr><tr><td><strong>SATA SSD</strong></td><td>Default. Best balance.</td><td>Sweet spot for now</td></tr><tr><td><strong>SAS HDD (7.2k or 10k)</strong></td><td>Cold tier, cheap bulk</td><td>Slower retrievals → may lose deals to faster provers</td></tr><tr><td><strong>SMR HDD</strong></td><td>Don&#39;t</td><td>SMR&#39;s write amplification kills proof latency</td></tr></tbody></table><p>You can mix tiers. The prover daemon supports a &quot;hot&quot; tier (recent + popular pieces) and a &quot;cold&quot; tier (rarely-retrieved). Caching strategies live in <code>prover/pkg/store/</code>.</p><h2 id="what-cpu" tabindex="-1">What CPU <a class="header-anchor" href="#what-cpu" aria-label="Permalink to &quot;What CPU&quot;">​</a></h2><p>PDP proofs are SHA-256 on a few KB at a time. Any modern CPU does this in microseconds. The CPU bottleneck (if any) is <strong>TLS termination + HTTPS retrieval throughput</strong> — i.e., serving clients, not generating proofs. Modern AES-NI CPUs handle gigabit-line-rate HTTPS without breaking 5% utilization.</p><h2 id="what-network" tabindex="-1">What network <a class="header-anchor" href="#what-network" aria-label="Permalink to &quot;What network&quot;">​</a></h2><p>The two metrics that matter:</p><ol><li><strong>Upload bandwidth.</strong> You&#39;re serving every retrieval. A 1 Gbps link means ~125 MB/s peak retrieval throughput. If your provers are popular, more = more revenue.</li><li><strong>Latency.</strong> Clients route to the fastest healthy prover. A prover in São Paulo serving Norwegian users will lose to one in Frankfurt. Place your hardware where the demand is.</li></ol><h2 id="geographic-placement" tabindex="-1">Geographic placement <a class="header-anchor" href="#geographic-placement" aria-label="Permalink to &quot;Geographic placement&quot;">​</a></h2><p>If you&#39;re starting with one node, put it where:</p><ul><li>Land and electricity are cheap (Nordic countries, Iceland)</li><li>Latency to ENS / NFT / web3 traffic is good (EU + NA East coast)</li><li>Regulatory environment is friendly (Norway, Switzerland, Singapore)</li></ul><p>If you&#39;re scaling to 5+ nodes, spread across continents. Prova&#39;s marketplace prefers geographically-diverse redundancy, which means cross-continent provers see preferential placement.</p><h2 id="stake-the-hidden-cost" tabindex="-1">Stake (the hidden cost) <a class="header-anchor" href="#stake-the-hidden-cost" aria-label="Permalink to &quot;Stake (the hidden cost)&quot;">​</a></h2><p>Your <strong>biggest hardware-equivalent expense</strong> is the USDC stake you must lock to commit capacity. The current ratio is ~$50 stake per TiB committed (configurable per the <code>ProverStaking.sol</code> parameters; check before registering).</p><p>For a 10 TB prover:</p><ul><li>Disk: $1,000-2,500 (one-time)</li><li>Network: $50-100/month</li><li>Stake: ~$500 USDC locked (refundable when you exit cleanly)</li><li>Slash exposure: up to your full stake if you fail badly</li></ul><p>Plan accordingly.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./earnings">Earnings calculator</a></li><li><a href="./become-a-prover">Become a prover</a></li></ul>',27)])])}const g=r(i,[["render",n]]);export{u as __pageData,g as default};
